request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?participant ?participantName
WHERE {
  ?model tai:originalId "3c1c7ac2bf4042fe9cd4ed34ce14a188" .
  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName .

  ?participant tai:belongsTo ?choreo ;
               a bboExt:Participant ;
               bbo:name ?participantName .

  FILTER(CONTAINS(LCASE(?participantName), "customer"))

  # Check if participant is involved in the task
  # Choreography tasks have participants linked via participantRef (often stored as IDs)
  # or via association/message flow. Let's check the structure.
  {
    ?task bboExt:participantRef ?partRef .
    FILTER(STRENDS(STR(?participant), ?partRef))
  }
  UNION
  {
    ?messageFlow tai:belongsTo ?choreo ;
                 a bboExt:MessageFlow ;
                 bboExt:sourceRef ?sourceId ;
                 bboExt:targetRef ?targetId .
    FILTER(STRENDS(STR(?task), ?sourceId) || STRENDS(STR(?task), ?targetId))
    FILTER(STRENDS(STR(?participant), ?sourceId) || STRENDS(STR(?participant), ?targetId))
  }
}
LIMIT 25
